<template>
  <div class="broadcast-page">
    <aside class="panel zone-panel">
      <div class="panel-title"><div><h2>广播分区</h2></div><el-icon><Connection /></el-icon></div>
      <div class="terminal-summary"><span>在线 <b class="green">{{ onlineCount }}</b></span><span>离线 <b class="red">{{ offlineCount }}</b></span><span>设备数 <b class="blue">{{ devices.length }}</b></span></div>
      <div class="device-tree">
        <div class="tree-root"><el-icon><Location /></el-icon><strong>主地块</strong><el-icon class="tree-arrow"><ArrowDown /></el-icon></div>
        <section v-for="building in buildingTree" :key="building.name" class="tree-building">
          <button type="button" class="tree-node tree-node--building" @click="buildingOpen[building.name] = !buildingOpen[building.name]"><el-icon><ArrowDown v-if="building.open" /><ArrowRight v-else /></el-icon><el-icon><OfficeBuilding /></el-icon><strong>{{ building.name }}</strong></button>
          <div v-if="building.open" class="tree-branch">
            <div v-for="floor in building.floors" :key="floor.name" class="tree-floor">
              <div class="tree-node tree-node--floor"><el-icon><Menu /></el-icon><span>{{ floor.name }}</span></div>
              <label v-for="device in floor.devices" :key="device.id" class="device-row" :class="{ offline: device.status === 'offline' }"><el-checkbox v-model="device.checked" :disabled="device.status === 'offline'" /><span class="status-dot" :class="device.status" /><span>{{ device.name }}</span><small>{{ device.status === 'online' ? '在线' : '离线' }}</small></label>
            </div>
          </div>
        </section>
      </div>
      <div class="zone-footer"><el-button type="primary" :icon="Plus" :disabled="checkedDevices.length === 0 || isBroadcasting" @click="addChecked">加入队列</el-button><span v-if="isBroadcasting">喊话中不可调整队列</span><span v-else>仅支持在线设备</span></div>
    </aside>

    <main class="map-canvas"><img :src="mapImage" alt="园区平面图" /><div class="map-wash" />
      <div class="map-filter"><el-radio-group v-model="mapFilter" size="small"><el-radio-button value="all">全部</el-radio-button><el-radio-button value="online">在线</el-radio-button><el-radio-button value="offline">离线</el-radio-button></el-radio-group></div>
      <button v-for="device in visibleDevices" :key="device.id" type="button" class="map-marker" :class="[device.status, { active: activeDevice?.id === device.id }]" :style="{ left: `${device.left}%`, top: `${device.top}%` }" @click="activeDevice = device"><span class="pulse" /><span class="marker-body"><el-icon><Microphone /></el-icon></span>
        <article v-if="activeDevice?.id === device.id" class="map-card" @click.stop><header><span class="status-dot" :class="device.status" /><strong>{{ device.name }}</strong><el-button text :icon="Close" @click="activeDevice = null" /></header><p>{{ device.location }}</p><div class="card-detail"><span>设备状态</span><b :class="device.status">{{ device.status === 'online' ? '在线' : '离线' }}</b></div><div class="card-detail"><span>队列状态</span><b :class="{ queued: isQueued(device.id) }">{{ isQueued(device.id) ? '是' : '否' }}</b></div><el-button v-if="device.status === 'online' && !isQueued(device.id)" type="primary" size="small" :disabled="isBroadcasting" @click="addToQueue(device)">加入队列</el-button><el-button v-else-if="isQueued(device.id)" type="danger" plain size="small" :disabled="isBroadcasting" @click="removeFromQueue(device.id)">移除</el-button><small v-if="isBroadcasting" class="lock-tip">喊话进行中，队列已锁定</small></article>
      </button>
      <div class="north">N</div>
    </main>

    <aside class="right-panel">
      <section class="panel intercom-panel"><div class="panel-title"><div><h2>喊话台控制</h2><span>广播主控终端</span></div><el-icon><Microphone /></el-icon></div><div class="intercom-status" :class="{ running: isBroadcasting }"><span class="signal"><i /><i /><i /></span><span>{{ isBroadcasting ? '已连通' : '网络就绪' }}</span></div><div class="timer">{{ formattedTime }}</div><p class="timer-tip">{{ isBroadcasting ? '正在向队列终端实时喊话' : '请添加广播终端后开始喊话' }}</p><el-button class="talk-button" :class="{ stop: isBroadcasting }" :disabled="!isBroadcasting && queue.length === 0" @click="toggleBroadcast"><el-icon><VideoPlay v-if="!isBroadcasting" /><SwitchButton v-else /></el-icon>{{ isBroadcasting ? '结束喊话' : '开始喊话' }}</el-button></section>
      <section class="panel queue-panel"><div class="panel-title"><div><h2>终端队列</h2><span>准备接收本次广播的设备</span></div><el-tag size="small" effect="plain">{{ queue.length }} 台</el-tag></div><div v-if="queue.length" class="queue-list"><article v-for="device in queue" :key="device.id" class="queue-item"><span class="queue-index">{{ queue.indexOf(device) + 1 }}</span><div><strong>{{ device.name }}</strong><small>{{ device.location }}</small></div><el-button link type="danger" :disabled="isBroadcasting" @click="removeFromQueue(device.id)">移除</el-button></article></div><div v-else class="empty-queue"><el-icon><MuteNotification /></el-icon><strong>暂无广播终端</strong><span>从左侧分区或地图添加设备</span></div><div v-if="isBroadcasting" class="queue-lock"><el-icon><Lock /></el-icon> 喊话执行中，已锁定队列操作</div></section>
    </aside>
  </div>
</template>

<script setup lang="ts">
import { computed, onBeforeUnmount, ref } from 'vue'
import { ArrowDown, ArrowRight, Close, Connection, Location, Lock, Menu, Microphone, MuteNotification, OfficeBuilding, Plus, SwitchButton, VideoPlay } from '@element-plus/icons-vue'
import { ElMessage } from 'element-plus'
import mapImage from '@/map.png'

type Status = 'online' | 'offline'
type Device = { id: string; name: string; building: string; floor: string; location: string; status: Status; left: number; top: number; checked: boolean }
const devices = ref<Device[]>([
  { id: 'CT-1F-PA-01', name: '大厅广播', building: 'CT楼', floor: 'CT-1F', location: 'CT楼 1F 大厅', status: 'online', left: 29, top: 39, checked: false },
  { id: 'CT-1F-PA-02', name: '电梯厅2广播', building: 'CT楼', floor: 'CT-1F', location: 'CT楼 1F 电梯厅2', status: 'online', left: 44, top: 31, checked: true },
  { id: 'CT-1F-PA-03', name: '电梯厅3广播', building: 'CT楼', floor: 'CT-1F', location: 'CT楼 1F 电梯厅3', status: 'online', left: 57, top: 52, checked: true },
  { id: 'FF-1F-PA-01', name: '货运通道广播', building: 'FF楼', floor: 'FF-1F', location: 'FF楼 1F 货运通道', status: 'offline', left: 52, top: 72, checked: false },
])
const buildingOpen = ref<Record<string, boolean>>({ 'CT楼': true, 'FF楼': true })
const queueIds = ref<string[]>(['CT-1F-PA-02', 'CT-1F-PA-03'])
const activeDevice = ref<Device | null>(null)
const mapFilter = ref<'all' | Status>('all')
const isBroadcasting = ref(false)
const elapsedSeconds = ref(0)
let timer: ReturnType<typeof setInterval> | undefined
const checkedDevices = computed(() => devices.value.filter((device) => device.checked && device.status === 'online'))
const queue = computed(() => queueIds.value.map((id) => devices.value.find((device) => device.id === id)).filter((device): device is Device => Boolean(device)))
const onlineCount = computed(() => devices.value.filter((device) => device.status === 'online').length)
const offlineCount = computed(() => devices.value.length - onlineCount.value)
const visibleDevices = computed(() => devices.value.filter((device) => mapFilter.value === 'all' || device.status === mapFilter.value))
const formattedTime = computed(() => `${String(Math.floor(elapsedSeconds.value / 60)).padStart(2, '0')}:${String(elapsedSeconds.value % 60).padStart(2, '0')}`)
const buildingTree = computed(() => ['CT楼', 'FF楼'].map((name) => ({ name, open: buildingOpen.value[name], floors: Array.from(new Set(devices.value.filter((device) => device.building === name).map((device) => device.floor))).map((floor) => ({ name: floor, devices: devices.value.filter((device) => device.floor === floor) })) })))
function isQueued(id: string) { return queueIds.value.includes(id) }
function addToQueue(device: Device) { if (!isQueued(device.id)) queueIds.value.push(device.id); device.checked = false; activeDevice.value = null; ElMessage.success(`已将${device.name}加入终端队列`) }
function addChecked() { const additions = checkedDevices.value.filter((device) => !isQueued(device.id)); additions.forEach((device) => { queueIds.value.push(device.id); device.checked = false }); if (additions.length) ElMessage.success(`已加入 ${additions.length} 台广播终端`); else ElMessage.info('所选设备均已在队列中') }
function removeFromQueue(id: string) { if (isBroadcasting.value) return; queueIds.value = queueIds.value.filter((queuedId) => queuedId !== id); if (activeDevice.value?.id === id) activeDevice.value = null }
function toggleBroadcast() { if (isBroadcasting.value) { isBroadcasting.value = false; if (timer) clearInterval(timer); ElMessage.success('喊话已结束，终端队列已解锁'); return }; isBroadcasting.value = true; elapsedSeconds.value = 0; timer = setInterval(() => { elapsedSeconds.value += 1 }, 1000); ElMessage.success(`已连通 ${queue.value.length} 台广播终端`) }
onBeforeUnmount(() => { if (timer) clearInterval(timer) })
</script>

<style lang="scss" scoped>
.broadcast-page { position: relative; width: 100%; height: 100%; min-height: 100%; overflow: hidden; background: #dbe7dc; color: #1e2d45; }.panel { border: 1px solid #e5eaf1; border-radius: 10px; background: #fff; box-shadow: 0 5px 20px rgba(38, 58, 90, .12); }.panel-title { display: flex; align-items: center; justify-content: space-between; padding: 17px 18px 13px; }.panel-title h2 { margin: 0; font-size: 15px; }.panel-title span { display: block; margin-top: 5px; color: #9aa5b5; font-size: 11px; }.panel-title > .el-icon { color: #8d9aac; font-size: 19px; }.zone-panel { position: absolute; z-index: 20; top: 16px; bottom: 16px; left: 16px; display: flex; width: 275px; flex-direction: column; }.queue-summary { display: flex; justify-content: space-between; padding: 10px 15px; border-block: 1px solid #edf0f5; color: #9ca7b6; font-size: 11px; }.queue-summary b { color: #4776e6; font-size: 14px; }.device-tree { flex: 1; overflow: auto; padding: 8px 10px; }.tree-root, .tree-node { display: flex; align-items: center; gap: 7px; min-height: 33px; color: #54647b; font-size: 12px; }.tree-root { padding: 0 5px; color: #2c405b; }.tree-arrow { margin-left: auto; }.tree-building__head { border: 0; background: transparent; }.tree-node--building { width: 100%; padding: 0 5px; cursor: pointer; }.tree-node--floor { padding-left: 28px; }.tree-branch { margin-left: 14px; border-left: 1px solid #e7ecf3; }.device-row { display: flex; align-items: center; gap: 7px; min-height: 39px; padding: 0 5px 0 43px; color: #506078; font-size: 12px; cursor: pointer; }.device-row:hover { background: #f4f7fc; }.device-row small { margin-left: auto; color: #1cac7e; font-size: 10px; }.device-row.offline { color: #a4adba; cursor: default; }.device-row.offline small { color: #e5686d; }.status-dot { display: inline-block; flex: none; width: 7px; height: 7px; border-radius: 50%; }.status-dot.online { background: #21b486; box-shadow: 0 0 0 3px #dff6ed; }.status-dot.offline { background: #e85f66; box-shadow: 0 0 0 3px #fde7e8; }.zone-footer { padding: 14px; border-top: 1px solid #edf0f5; }.zone-footer .el-button { width: 100%; }.zone-footer span { display: block; margin-top: 8px; color: #9ea9b8; text-align: center; font-size: 10px; }.map-canvas { position: absolute; inset: 0; overflow: hidden; }.map-canvas > img { width: 100%; height: 100%; object-fit: cover; filter: saturate(.66) contrast(.94); }.map-wash { position: absolute; inset: 0; background: rgba(220, 236, 222, .15); }.map-label { position: absolute; z-index: 3; top: 15px; left: 308px; display: flex; align-items: center; gap: 6px; padding: 8px 11px; border: 1px solid rgba(226,232,240,.9); border-radius: 6px; color: #65758a; background: rgba(255,255,255,.9); box-shadow: 0 3px 12px rgba(45,62,83,.1); font-size: 11px; }.map-marker { position: absolute; z-index: 3; padding: 0; border: 0; background: none; transform: translate(-50%, -50%); cursor: pointer; }.marker-body { display: grid; place-items: center; width: 30px; height: 30px; border: 3px solid #fff; border-radius: 50%; color: #fff; box-shadow: 0 2px 7px rgba(32,54,74,.3); }.map-marker.online .marker-body { background: #20ad82; }.map-marker.offline .marker-body { background: #e85e66; }.pulse { position: absolute; inset: -5px; border-radius: 50%; opacity: .3; animation: pulse 2s infinite; }.online .pulse { background: #20ad82; }.offline .pulse { background: #e85e66; }.map-marker.active { z-index: 9; }.map-card { position: absolute; top: 42px; left: 50%; width: 216px; padding: 12px; transform: translateX(-50%); border: 1px solid #e1e8f0; border-radius: 8px; background: #fff; box-shadow: 0 8px 22px rgba(29,49,78,.18); text-align: left; }.map-card header { display: flex; align-items: center; gap: 7px; }.map-card header strong { flex: 1; color: #34485f; font-size: 12px; }.map-card p { margin: 8px 0; color: #98a4b2; font-size: 10px; }.card-detail { display: flex; justify-content: space-between; padding: 6px 0; border-top: 1px solid #f0f3f7; color: #8794a5; font-size: 11px; }.card-detail b { color: #1cab7f; }.card-detail b.offline { color: #e46168; }.card-detail b.queued { color: #4776e6; }.map-card .el-button { width: 100%; margin-top: 9px; }.lock-tip { display: block; margin-top: 7px; color: #a0aab7; text-align: center; font-size: 10px; }.map-legend { position: absolute; right: 392px; bottom: 20px; display: flex; gap: 14px; padding: 8px 12px; border-radius: 6px; background: rgba(255,255,255,.88); color: #69788c; font-size: 10px; }.map-legend i { display: inline-block; width: 7px; height: 7px; margin-right: 5px; border-radius: 50%; }.map-legend .online { background: #20ad82; }.map-legend .offline { background: #e85e66; }.queued-dot { background: #4b77df; }.north { position: absolute; right: 29px; bottom: 21px; color: #68788d; font-weight: 700; }.right-panel { position: absolute; z-index: 20; top: 16px; right: 16px; bottom: 16px; display: grid; grid-template-rows: 285px minmax(0, 1fr); gap: 12px; width: 360px; }.intercom-panel { padding-bottom: 16px; text-align: center; }.intercom-status { display: flex; align-items: center; justify-content: center; gap: 7px; color: #28a87f; font-size: 12px; }.intercom-status.running { color: #e15e65; }.signal { display: flex; align-items: end; gap: 2px; height: 13px; }.signal i { width: 3px; border-radius: 2px; background: currentColor; }.signal i:nth-child(1) { height: 5px; }.signal i:nth-child(2) { height: 9px; }.signal i:nth-child(3) { height: 13px; }.timer { margin-top: 10px; color: #2b405d; font-family: Arial, sans-serif; font-size: 45px; font-weight: 600; letter-spacing: 2px; }.timer-tip { margin: 5px 0 15px; color: #9aa5b4; font-size: 11px; }.talk-button { width: calc(100% - 36px); height: 38px; color: #fff; border-color: #4c78df; background: #4c78df; }.talk-button.stop { border-color: #e25e65; background: #e25e65; }.queue-panel { position: relative; display: flex; min-height: 0; flex-direction: column; overflow: hidden; }.queue-list { flex: 1; overflow: auto; padding: 4px 12px 12px; }.queue-item { display: flex; align-items: center; gap: 9px; min-height: 56px; border-bottom: 1px solid #f0f3f7; }.queue-index { display: grid; place-items: center; width: 20px; height: 20px; border-radius: 5px; color: #6380c0; background: #eef3fb; font-size: 10px; }.queue-item div { min-width: 0; flex: 1; }.queue-item strong, .queue-item small { display: block; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }.queue-item strong { color: #465971; font-size: 12px; }.queue-item small { margin-top: 5px; color: #a0abb8; font-size: 10px; }.empty-queue { display: flex; flex: 1; align-items: center; justify-content: center; flex-direction: column; gap: 8px; color: #9da8b6; }.empty-queue .el-icon { color: #c0cad7; font-size: 32px; }.empty-queue strong { color: #718096; font-size: 13px; }.empty-queue span { font-size: 10px; }.queue-lock { padding: 10px 14px; color: #a07961; background: #fff8ed; font-size: 10px; text-align: center; }.queue-lock .el-icon { margin-right: 4px; vertical-align: -2px; }@keyframes pulse { 0%,100% { transform: scale(.7); opacity: .18; } 50% { transform: scale(1.1); opacity: .42; } }@media (max-width: 1100px) { .zone-panel { width: 245px; }.right-panel { width: 330px; }.map-label { left: 275px; }.map-legend { right: 360px; } }@media (max-width: 720px) { .zone-panel { top: 10px; right: 10px; bottom: auto; left: 10px; width: auto; max-height: 42%; }.right-panel { top: 46%; right: 10px; bottom: 10px; width: calc(100% - 20px); }.map-label { top: calc(42% + 20px); left: 10px; }.map-legend { right: 10px; bottom: 10px; } }
.terminal-summary { display: flex; justify-content: space-around; padding: 11px; border-block: 1px solid #edf0f5; color: #9aa6b5; font-size: 11px; }.terminal-summary b { margin-left: 3px; font-size: 15px; }.green { color: #1cad80; }.red { color: #e5636a; }.blue { color: #4b77df; }.map-filter { position: absolute; z-index: 5; top: 14px; left: 300px; padding: 5px; border: 1px solid rgba(225,231,239,.9); border-radius: 6px; background: rgba(255,255,255,.9); box-shadow: 0 3px 12px rgba(45,62,83,.1); }
</style>
